<script setup lang="ts">
import { canonicalPath, pageKindLabel, type ContentPage, type ManifestPage } from '../../shared/content'
import { manifest, pageById, renderLegacy } from '../utils/content'
const props=defineProps<{page:ContentPage}>();const html=computed(()=>renderLegacy(props.page));const related=computed(()=>props.page.backlinks.map(id=>pageById.get(id)).filter((p):p is ManifestPage=>!!p).slice(0,20));const primaryWorks=manifest.pages.filter(p=>p.type==='annotated-text');const rootId=`content-${props.page.id}`
</script>
<template><div class="reader-shell"><SiteHeader/><main class="reader-main"><article class="reading-card"><header class="page-header"><p class="eyebrow">{{pageKindLabel(page.type)}}</p><h1>{{page.title}}</h1><nav class="work-nav" aria-label="Works" v-if="page.type==='annotated-text'"><NuxtLink v-for="work in primaryWorks" :key="work.id" :to="canonicalPath(work)" :aria-current="work.id===page.id?'page':undefined">{{work.title}}</NuxtLink></nav></header><div :id="rootId" class="legacy-content" v-html="html"/><section v-if="related.length" class="related" aria-labelledby="related-heading"><h2 id="related-heading">Related pages</h2><ul><li v-for="item in related" :key="item.id"><NuxtLink :to="canonicalPath(item)">{{item.title}}</NuxtLink></li></ul></section><footer class="page-footer"><div><span>Source record</span><code>{{page.sourceFile}}</code></div><div><IssueLink :id="page.id" :title="page.title" :type="page.type"/></div></footer></article></main><LegacyEnhancements :root-id="rootId"/></div></template>
